{
  "executive_summary": "A courier assignment system requiring sub-200ms latency, strong consistency (no double-assignment), and availability during single-node database failures. These requirements create a well-known CAP theorem tension — strong consistency and high availability conflict during network partitions. However, the specific requirement (survive a DB node failure, not arbitrary partitions) is achievable via synchronous replication with automatic failover. The architecture uses PostgreSQL with Patroni for HA, row-level pessimistic locking for double-assignment prevention, and a lean service design appropriate for a 2-engineer team.",

  "architecture": {
    "components": [
      {
        "name": "Assignment Service",
        "responsibility": "Receives order-placed events, selects the optimal available courier, and atomically assigns them. Owns the core assignment algorithm (proximity, capacity, load-balancing).",
        "boundaries": "Owns courier availability state and assignment transactions. Does NOT own order lifecycle or courier profile data."
      },
      {
        "name": "Courier Availability Cache",
        "responsibility": "In-process materialized view of available couriers with geospatial index, rebuilt from DB on startup and kept consistent via DB LISTEN/NOTIFY. Enables sub-200ms reads without hitting the DB for candidate selection.",
        "boundaries": "Read-only projection. All writes go through the Assignment Service's transactional path against the DB."
      },
      {
        "name": "PostgreSQL Primary + Synchronous Standby (Patroni-managed)",
        "responsibility": "Source of truth for courier assignments and availability. Synchronous replication ensures zero data loss on failover. Patroni handles automatic leader election on node failure.",
        "boundaries": "Owns all persistent state. Synchronous commit guarantees the standby has every committed transaction before the primary acknowledges."
      },
      {
        "name": "Order Gateway",
        "responsibility": "API entry point that receives order placement requests and dispatches to the Assignment Service. Handles request validation, authentication, and timeout enforcement.",
        "boundaries": "Stateless. Does not own business logic beyond routing and validation."
      }
    ],
    "interfaces": [
      {
        "from": "Order Gateway",
        "to": "Assignment Service",
        "contract": "POST /assign {order_id, pickup_location, delivery_location} → {courier_id, estimated_pickup_time} | 409 Conflict | 503 Unavailable",
        "coupling_type": "synchronous RPC (internal, same process or sidecar)"
      },
      {
        "from": "Assignment Service",
        "to": "PostgreSQL",
        "contract": "BEGIN → SELECT courier_id FROM couriers WHERE status='available' ORDER BY distance(...) LIMIT 1 FOR UPDATE SKIP LOCKED → UPDATE couriers SET status='assigned', current_order_id=? → COMMIT",
        "coupling_type": "synchronous transactional (connection pool via PgBouncer)"
      },
      {
        "from": "PostgreSQL Primary",
        "to": "PostgreSQL Standby",
        "contract": "Synchronous streaming replication — primary waits for standby WAL flush before acknowledging COMMIT",
        "coupling_type": "synchronous replication"
      },
      {
        "from": "Assignment Service",
        "to": "Courier Availability Cache",
        "contract": "In-process read for candidate shortlisting; DB LISTEN/NOTIFY for cache invalidation on courier status changes",
        "coupling_type": "in-process, eventually consistent (read path only — write path always hits DB)"
      }
    ],
    "data_flow": "1) Order Gateway receives placement request. 2) Assignment Service queries in-process geo-indexed cache to shortlist ~5 nearest available couriers (< 1ms). 3) Assignment Service opens DB transaction, issues SELECT ... FOR UPDATE SKIP LOCKED against shortlisted courier IDs to atomically claim the first available one (~5-15ms with connection pool). 4) On successful lock, UPDATE courier status to 'assigned' and COMMIT (~5-10ms including synchronous replication flush). 5) Return assignment to caller. Total: well under 200ms. If all shortlisted couriers are already locked by concurrent transactions, SKIP LOCKED skips them — expand candidate set or return 503.",
    "patterns_used": [
      {
        "pattern": "Pessimistic Locking with SKIP LOCKED",
        "rationale": "SELECT FOR UPDATE SKIP LOCKED is the gold standard for work-queue-style exclusive assignment in PostgreSQL. It prevents double-assignment without deadlocks — concurrent transactions simply skip already-locked rows instead of blocking. This directly satisfies the strong consistency requirement."
      },
      {
        "pattern": "Synchronous Replication with Automatic Failover (Patroni)",
        "rationale": "Satisfies both consistency (zero data loss — standby always has latest committed state) and availability during single-node failure (Patroni promotes standby to primary within seconds). This is the practical resolution of the CAP tension for the 'DB node failure' scenario."
      },
      {
        "pattern": "In-Process Materialized View (Geo-Indexed Cache)",
        "rationale": "Avoids a network round-trip for candidate selection, keeping latency well under 200ms. The cache is a read-optimization only — the DB remains authoritative. LISTEN/NOTIFY keeps it reasonably fresh without polling."
      },
      {
        "pattern": "Connection Pooling (PgBouncer)",
        "rationale": "With only 2 engineers, operational simplicity matters. PgBouncer avoids connection storms and keeps DB latency predictable under load, critical for the 200ms SLA."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Courier Assignment",
        "classification": "core",
        "aggregates": [
          {
            "name": "Courier",
            "root_entity": "Courier",
            "invariants": [
              "A courier with status='assigned' must have exactly one current_order_id",
              "A courier cannot be assigned to two orders simultaneously (enforced by DB lock + status transition)",
              "Status transitions: available → assigned → delivering → available"
            ],
            "entities": ["Courier"],
            "value_objects": ["Location", "AssignmentWindow", "CourierCapability"]
          }
        ]
      },
      {
        "name": "Order Management",
        "classification": "supporting",
        "aggregates": [
          {
            "name": "Order",
            "root_entity": "Order",
            "invariants": [
              "An order must have a courier assigned before transitioning to 'dispatched'",
              "An order can only be assigned to one courier"
            ],
            "entities": ["Order"],
            "value_objects": ["PickupLocation", "DeliveryLocation", "OrderTimeline"]
          }
        ]
      }
    ],
    "context_map": [
      {
        "upstream": "Order Management",
        "downstream": "Courier Assignment",
        "relationship": "Customer-Supplier — Order Management publishes order-placed events; Courier Assignment consumes them and owns the assignment decision. Order Management does not dictate courier selection logic."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "Synchronous replication over asynchronous",
      "gains": "Zero data loss on failover — a committed assignment is guaranteed to exist on the standby. Prevents the nightmare scenario where a courier is assigned, the primary dies, the standby promotes without that assignment, and another request double-assigns the same courier.",
      "sacrifices": "Write latency increases by ~2-5ms (network round-trip to standby for WAL flush). Throughput ceiling is lower. If the standby is unreachable, the primary must either block writes (sacrificing availability) or switch to async (sacrificing consistency).",
      "alternatives_considered": [
        "Asynchronous replication — faster writes but risks data loss and double-assignment on failover. Unacceptable given requirement #2.",
        "Multi-master (e.g., CockroachDB) — stronger consistency guarantees but significantly higher operational complexity for a 2-person team."
      ]
    },
    {
      "decision": "PostgreSQL + Patroni over distributed database (CockroachDB, Spanner)",
      "gains": "Dramatically simpler operations for a 2-engineer team. PostgreSQL is the most widely understood database. Patroni is battle-tested for HA. SKIP LOCKED is a native, well-optimized feature.",
      "sacrifices": "Single-region constraint — failover takes 5-30 seconds during which writes are unavailable. No horizontal write scaling. If the platform grows to millions of concurrent assignments, this architecture needs rethinking.",
      "alternatives_considered": [
        "CockroachDB — native distributed consistency but steep learning curve, more complex debugging, and higher infra cost for a 2-person team.",
        "Redis with Redlock — sub-millisecond latency but Redlock has well-documented safety issues (Martin Kleppmann's analysis). Unacceptable for a financial/operational invariant like no-double-assignment."
      ]
    },
    {
      "decision": "Pessimistic locking (SELECT FOR UPDATE SKIP LOCKED) over optimistic concurrency",
      "gains": "Guaranteed no double-assignment at the database level. SKIP LOCKED eliminates deadlocks and contention — concurrent assigners simply claim different couriers. Extremely predictable latency.",
      "sacrifices": "Transactions hold row locks briefly, which limits extreme concurrency on the same courier rows. Not an issue at typical logistics scale.",
      "alternatives_considered": [
        "Optimistic locking with version column — requires retry loops, which add latency variance and complexity. Worse for this work-queue pattern.",
        "Application-level distributed lock (Redis) — adds a failure mode (lock service outage) and split-brain risk. Unnecessary when the DB can do it natively."
      ]
    },
    {
      "decision": "In-process geo cache over external cache (Redis)",
      "gains": "Eliminates a network hop (~1-3ms saved), removes an infrastructure dependency, simpler for a small team to operate. Cache is a read-optimization only so staleness has bounded impact (the DB transaction is the safety net).",
      "sacrifices": "Each service instance has its own cache — memory duplication. Cache staleness window depends on LISTEN/NOTIFY latency (~10-50ms). Not suitable if the service scales to many instances.",
      "alternatives_considered": [
        "Redis with geospatial indexes — adds operational burden (another stateful service to manage) and a network hop. Overkill at this team size.",
        "PostGIS query directly — viable but adds 5-15ms per assignment for spatial query, eating into the 200ms budget."
      ]
    }
  ],

  "flexibility_points": [
    {
      "area": "Assignment Algorithm",
      "evolution_path": "The courier selection logic (currently nearest-available) is isolated in the Assignment Service. It can evolve to consider courier ratings, delivery type matching, workload balancing, or ML-based scoring without changing the consistency or availability architecture."
    },
    {
      "area": "Scaling to Multiple Regions",
      "evolution_path": "If the platform expands geographically, each region can run its own Assignment Service + PostgreSQL cluster (couriers don't cross regions). This partitions the problem naturally without needing distributed transactions."
    },
    {
      "area": "Event-Driven Integration",
      "evolution_path": "The DB LISTEN/NOTIFY pattern can be replaced with a proper event bus (Kafka, NATS) if downstream consumers (analytics, ETA prediction, customer notifications) need assignment events. The core transactional path remains unchanged."
    }
  ],

  "rigidity_points": [
    {
      "area": "PostgreSQL as the consistency backbone",
      "reason": "The entire double-assignment prevention relies on PostgreSQL's transactional guarantees and SKIP LOCKED. Migrating to a different database requires re-implementing this critical invariant. This is intentional rigidity — the consistency guarantee is too important to abstract away."
    },
    {
      "area": "Synchronous replication requirement",
      "reason": "Cannot be relaxed without risking double-assignment on failover. This is a non-negotiable architectural constraint derived directly from the business requirement."
    },
    {
      "area": "Single-writer (primary) architecture",
      "reason": "All assignment writes must go through one PostgreSQL primary. This limits write throughput to what a single node can handle (~10K-50K transactions/sec). Sufficient for logistics but rigid if requirements change dramatically."
    }
  ],

  "risks": [
    {
      "risk": "Patroni failover window (5-30 seconds) during which writes are unavailable, violating the availability requirement",
      "severity": "high",
      "mitigation": "Accept a brief unavailability window during failover — this is the honest trade-off when choosing consistency over availability during a failure event. Document this in the SLA. Implement client-side retry with backoff so orders placed during failover are assigned within seconds of recovery. Monitor failover frequency — if it's frequent, investigate root cause (hardware, network)."
